import asyncio
from aiocoap import Context, Message, Code, Resource

class SensorResource(Resource):
    async def render_get(self, request):
        # Simulate temperature reading
        temp = 25.0
        response = Message(code=Code.CONTENT, payload=str(temp).encode('utf-8'))
        return response

class ActuatorResource(Resource):
    async def render_put(self, request):
        new_state = request.payload.decode('utf-8')
        # Simulate actuator state change
        print(f"Light state changed to: {new_state}")
        response = Message(code=Code.CHANGED)
        return response

async def main():
    context = await Context.create_server_context()

    root = Resource("root")
    sensors = Resource("sensors")
    actuators = Resource("actuators")

    temp_sensor = SensorResource()
    light_actuator = ActuatorResource()

    sensors.add_resource(["temp"], temp_sensor)
    actuators.add_resource(["light"], light_actuator)

    root.add_child("sensors", sensors)
    root.add_child("actuators", actuators)

    context.set_root_node(root)

    await asyncio.Future()  # Run forever

if __name__ == "__main__":
    asyncio.run(main())